-- ============================================= -- DerewolPrint — Subscription System Migration -- Execute this SQL in Supabase SQL Editor -- ============================================= -- Add plan column to subscriptions table ALTER TABLE subscriptions ADD COLUMN IF NOT EXISTS plan TEXT DEFAULT '1month' CHECK (plan IN ('trial', '1month', '2months', '3months')); -- Add notes column for admin notes ALTER TABLE subscriptions ADD COLUMN IF NOT EXISTS notes TEXT; -- Create function for automatic trial subscription CREATE OR REPLACE FUNCTION create_trial_subscription(p_printer_id UUID) RETURNS void AS $$ BEGIN INSERT INTO subscriptions ( printer_id, activation_code, plan, duration_days, amount, payment_method, status, activated_at, expires_at ) VALUES ( p_printer_id, 'TRIAL-' || UPPER(SUBSTRING(p_printer_id::text, 1, 8)), 'trial', 7, 0, 'manual', 'active', NOW(), NOW() + INTERVAL '7 days' ) ON CONFLICT DO NOTHING; END; $$ LANGUAGE plpgsql; -- Create index for faster subscription queries CREATE INDEX IF NOT EXISTS idx_subscriptions_printer_status ON subscriptions(printer_id, status); CREATE INDEX IF NOT EXISTS idx_subscriptions_expires ON subscriptions(expires_at) WHERE status = 'active'; -- Grant permissions GRANT USAGE ON SCHEMA public TO authenticated; GRANT ALL ON subscriptions TO authenticated; GRANT EXECUTE ON FUNCTION create_trial_subscription TO authenticated;